import { labelCorrectionParser } from './label-correction-parser';
import { bubbleCorrectionParser } from './bubble-correction-parser';
import { markerCorrectionParser } from './marker-correction-parser';
import { getKey } from './correction-parser-helpers';

export let correctionParserMap = {
    label: labelCorrectionParser,
    bubble: bubbleCorrectionParser,
    marker: markerCorrectionParser
};

export function getCorrectionParser(mode, encodeType, index, chart) {
    let key = getKey(mode, encodeType, index),
        cached = chart.cache.correction;

    // Serve correction operator from cache. If not cached, get the operators
    return cached[key] ? [cached[key]] : correctionParserMap[mode](encodeType, index, chart);
}
